import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How much fat should you eat per day?", a: "Most adults can use about 20% to 35% of calories from fat, adjusted for goals and diet style." },
  { q: "What is the difference between saturated and unsaturated fat?", a: "Unsaturated fats are generally considered heart-healthier fats, while saturated fats are usually limited to a smaller portion of daily calories." },
  { q: "What are trans fats and why are they bad?", a: "Artificial trans fats can raise heart disease risk and are best kept as close to zero as possible." },
  { q: "Does eating fat make you fat?", a: "Dietary fat does not automatically cause fat gain. Weight change depends mostly on total calorie balance over time." },
  { q: "What are healthy fat sources?", a: "Healthy fat sources include olive oil, avocado, nuts, seeds, fatty fish, eggs, and some dairy foods." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const activityMap: Record<string, number> = { Sedentary: 1.2, Light: 1.375, Moderate: 1.55, Active: 1.725, Athlete: 1.9 };
const fatPct: Record<string, number> = { "Lose weight": 0.25, Maintain: 0.3, "Gain muscle": 0.25, Keto: 0.7, Mediterranean: 0.35 };
function bmr(gender: string, age: number, heightCm: number, weightKg: number) { return 10 * weightKg + 6.25 * heightCm - 5 * age + (gender === "Male" ? 5 : -161); }

export default function FatIntakeCalculator() {
  const [age, setAge] = useState(30);
  const [gender, setGender] = useState("Male");
  const [height, setHeight] = useState(175);
  const [weight, setWeight] = useState(80);
  const [activity, setActivity] = useState("Moderate");
  const [goal, setGoal] = useState("Maintain");
  const result = useMemo(() => {
    const maintenance = bmr(gender, age, height, weight) * activityMap[activity];
    const calories = goal === "Lose weight" ? maintenance - 500 : goal === "Gain muscle" ? maintenance + 300 : maintenance;
    const pct = fatPct[goal] || 0.3;
    return { calories, pct, fat: calories * pct / 9, saturated: calories * 0.1 / 9, unsaturated: calories * Math.max(0, pct - 0.1) / 9 };
  }, [age, gender, height, weight, activity, goal]);
  const rows = [["Standard Diet", "20-35%", "44-78g", "Under 22g", "General health"], ["Low Fat", "15-25%", "33-56g", "Under 22g", "Lower fat preference"], ["High Fat", "35-45%", "78-100g", "Under 22g", "Satiety"], ["Keto", "60-75%", "133-167g", "Under 22g", "Ketogenic diets"], ["Mediterranean", "30-40%", "67-89g", "Under 22g", "Heart-friendly eating"], ["Athletic", "20-30%", "44-67g", "Under 22g", "Performance balance"]];
  return (
    <>
      <SEOHead title="Free Fat Intake Calculator Online - Calculate Daily Fat Intake Instantly | CalcHive" description="Free online fat intake calculator. Calculate your recommended daily fat intake in grams based on your goal, body stats and activity level instantly. 100% free, no signup required." canonical="/fat-intake-calculator" keywords="free fat intake calculator, daily fat intake calculator free online, how much fat per day calculator free, dietary fat calculator free, fat grams per day calculator free" category="Health Calculators" breadcrumbName="Free Fat Intake Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Fat Intake Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate daily dietary fat targets with saturated, unsaturated, and trans fat guidance.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Age</label><input type="number" value={age} onChange={(e) => setAge(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Gender</label><select value={gender} onChange={(e) => setGender(e.target.value)} className={inputClass}><option>Male</option><option>Female</option></select></div><div><label className="text-sm font-semibold block mb-2">Height (cm)</label><input type="number" value={height} onChange={(e) => setHeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Weight (kg)</label><input type="number" value={weight} onChange={(e) => setWeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Activity level</label><select value={activity} onChange={(e) => setActivity(e.target.value)} className={inputClass}>{Object.keys(activityMap).map((x) => <option key={x}>{x}</option>)}</select></div><div><label className="text-sm font-semibold block mb-2">Goal</label><select value={goal} onChange={(e) => setGoal(e.target.value)} className={inputClass}>{Object.keys(fatPct).map((x) => <option key={x}>{x}</option>)}</select></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Daily Fat Intake</p><p className="text-5xl sm:text-6xl font-black text-white">{Math.round(result.fat)}g</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Fat calories</p><p className="text-lg font-extrabold">{Math.round(result.pct * 100)}%</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Saturated limit</p><p className="text-lg font-extrabold">{Math.round(result.saturated)}g</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Unsaturated target</p><p className="text-lg font-extrabold">{Math.round(result.unsaturated)}g</p></div></div></section><MedicalDisclaimer /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Your Daily Fat Intake for Free</h2><p className="text-muted-foreground leading-relaxed">Estimate daily calories, assign a goal-based fat percentage, then divide fat calories by 9 to convert to grams.</p><h2 className="text-2xl font-bold">How Much Fat Should You Eat Per Day</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Daily Fat Intake by Diet Type and Goal</caption><thead className="bg-muted/60"><tr>{["Diet Type", "Fat % of Calories", "Daily Fat on 2000 cal", "Saturated Fat Limit", "Best For"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((r) => <tr key={r[0]}>{r.map((c) => <td key={c} className="py-2.5 px-3">{c}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free Daily Fat Needs Calculator for Every Diet Goal</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/fat-intake-calculator" headingLevel="h3" /></main>
    </>
  );
}


